{
  "summary": "This paper presents a comprehensive benchmark and comparative study of continual learning methods applied to multiple pre-trained language models (PLMs) on diverse NLP tasks. It reveals that catastrophic forgetting is prevalent across PLMs, with experience replay methods being the most effective mitigation strategy, and provides novel layer-wise probing analyses to understand internal forgetting dynamics.",
  "strengths": [
    {
      "point": "Comprehensive benchmark combining multiple CL settings, datasets, methods, and PLMs",
      "evidence": "The benchmark includes task-IL and class-IL settings, three diverse NLP datasets, six baseline CL methods, and five representative PLMs."
    },
    {
      "point": "Novel layer-wise probing analysis revealing internal forgetting patterns",
      "evidence": "Prototype-based probing shows forgetting occurs in classifier and middle layers, with replay methods better preserving representations."
    }
  ],
  "weaknesses": [
    {
      "point": "Lack of comparison to recent or advanced continual learning methods",
      "evidence": "No evaluation of parameter-efficient fine-tuning or prompt-based CL methods limits novelty and practical relevance."
    },
    {
      "point": "Insufficient methodological and experimental details affecting reproducibility",
      "evidence": "Missing hyperparameter details, unclear prototype construction, and ambiguous definitions of CL settings reduce reproducibility."
    }
  ],
  "questions": [
    {
      "question": "How do replay buffer size and sampling strategies affect continual learning performance?",
      "motivation": "Understanding sensitivity to replay buffer design is critical for optimizing experience replay methods."
    },
    {
      "question": "How do findings generalize to larger PLMs, other languages, and generation or multimodal tasks?",
      "motivation": "Extending results beyond English classification tasks is important for broader applicability in NLP."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
